// src/components/Profile.js
import React from 'react';
import { useAuth } from '../AuthContext';

function Profile() {
  const { user, isAuthenticated, isLoading, authError } = useAuth();

  if (isLoading) {
    return <p>Loading user data...</p>;
  }

  if (authError) {
    return <p style={{ color: 'red' }}>Authentication Error: {authError}</p>;
  }

  if (!isAuthenticated || !user) {
    return <p>Please log in to see your profile.</p>;
  }

  return (
    <div>
      <h2>User Profile</h2>
      <p><strong>Subject (sub):</strong> {user.sub}</p>
      {user.name && <p><strong>Name:</strong> {user.name}</p>}
      {user.email && <p><strong>Email:</strong> {user.email}</p>}
      {user.picture && <p><img src={user.picture} alt="Profile" style={{ width: '100px', borderRadius: '50%' }} /></p>}
      <p><strong>Issued At (iat):</strong> {new Date(user.iat * 1000).toLocaleString()}</p>
      <p><strong>Expires At (exp):</strong> {new Date(user.exp * 1000).toLocaleString()}</p>
      {/* You can display more claims from the id_token here */}
      <h3>Raw ID Token Claims:</h3>
      <pre style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-all', backgroundColor: '#f0f0f0', padding: '10px', borderRadius: '5px' }}>
        {JSON.stringify(user, null, 2)}
      </pre>
    </div>
  );
}

export default Profile;

