// src/pages/CallbackPage.js
import React, { useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../AuthContext';

function CallbackPage() {
  const location = useLocation();
  const navigate = useNavigate();
  const { handleAuthCallback, authError } = useAuth();

  useEffect(() => {
    const searchParams = new URLSearchParams(location.search);
    handleAuthCallback(searchParams);
  }, [location.search, handleAuthCallback]);

  // Redirect after handling callback
  useEffect(() => {
    // Only navigate if there's no error, indicating successful processing
    // and if authentication state is now set
    if (!authError) {
      const timer = setTimeout(() => {
        // Use replace: true to prevent going back to callback page
        navigate('/', { replace: true }); 
      }, 100); // Small delay to ensure state update is processed
      return () => clearTimeout(timer);
    }
    // If there's an error, the user might see the error message before manual navigation
  }, [authError, navigate]);

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial, sans-serif', textAlign: 'center' }}>
      <h2>Authenticating...</h2>
      {authError && <p style={{ color: 'red' }}>Error during authentication: {authError}</p>}
      <p>Please wait while we process your login.</p>
    </div>
  );
}

export default CallbackPage;

